+        assert_eq!(report.status, fcp_core::SelfCheckStatus::Failed);
+        assert_eq!(report.reason_code.as_deref(), Some("self_check_runtime"));
+        assert!(
+            report
+                .message
+                .as_deref()
+                .is_some_and(|message| message.contains("subprocess exited"))
+        );
+    }
